const getTag = (ast: Schema.Schema.Any["ast"]): string | undefined => {
  if (ast._tag === "Transformation") return getTag(ast.to)
  if (ast._tag === "Suspend") return getTag(ast.f())
  if (ast._tag !== "TypeLiteral") return undefined
  const property = ast.propertySignatures.find((property) => property.name === "_tag")
  return property?.type._tag === "Literal" && typeof property.type.literal === "string"
    ? property.type.literal
    : undefined
}

